import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Link Validator","description":"","frontmatter":{"title":"Link Validator","slug":"link-validator"},"headers":[],"relativePath":"marketer-hub/link-validator.md","filePath":"marketer-hub/link-validator.md"}'),n={name:"marketer-hub/link-validator.md"};function r(l,e,s,h,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Given all the different variables at play in a deep linking scenario, from click location (Safari, Instagram, Facebook, TikTok, etc.) to operating system, it’s difficult to know what an end-user will actually see when they click your deep link.</p><p>To help you navigate this, Branch has the <strong>Link Validator</strong> tool within the Dashboard. This tool helps you test the links you create, so you can feel confident about what your users will see when they click on your deep links.</p><p>The Link Validator tool helps you determine what the expected outcome should be when your customers start using your links, giving you something to test against once your links are actually out in the wild.</p><h2 id="link-types" tabindex="-1">Link Types <a class="header-anchor" href="#link-types" aria-label="Permalink to &quot;Link Types&quot;">​</a></h2><p>Please note that the Link Validator only accepts the following link types:</p><ul><li><p>Branch <a href="./create-quick-links.html">Short Links</a> created within the Branch Dashboard.</p></li><li><p>Branch Links created using one of our link-generating APIs:</p><ul><li><a href="./quick-links-api.html">Short Links API</a></li><li><a href="./deep-linking-api.html">Deep Linking API</a></li></ul></li></ul><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>The Link Validator is made to be a user-friendly way of seeing how your link will behave based on who your customer is and where they are clicking the link from.</p><p>To try the Link Validator tool:</p><ol><li>Go to the <a href="https://dashboard.branch.io/quick-links/validator" target="_blank" rel="noreferrer">Branch Dashboard</a> and use the left-side navigation bar to click on <strong>LinkHub</strong>, which is in the <strong>Campaigns</strong> section.</li><li>Click the <strong>Link</strong> <strong>Validator</strong> tab on the <strong>LinkHub</strong> page.</li><li>Copy the URL for one of your Branch Links, making sure it is of the appropriate <a href="./link-validator.html#link-types">type</a>.</li><li>Paste the URL of the Branch Link into the validation box, and click the <strong>Validate</strong> button.</li></ol><p>The first section that appears when you validate the link is a small overview module summarizing details about the link. It contains the link itself, the name of the link, who created it, when they created it, and how it was created. Using the icons, you can also copy the link, edit the link, or view analytics for the link.</p><p>.png)</p><p>The next section lets you lets you see where users go when they click your link. In this section, you will need to set the user&#39;s iOS, where they were clicking from, and where they have the app installed.</p><p>.png)</p><p>Once you select options for these three variables, an image will appear that depicts your user&#39;s flow.</p><p>In the example above, the values selected were <strong>iOS</strong>, <strong>Facebook</strong>, and <strong>Installed</strong>. The resulting diagram shows that a user would be taken from Facebook to a Branch Deepview while the app is loading, then to the app itself.</p><p>Test various scenarios until you are sure you&#39;re seeing the behavior you expect.</p><p>The final section is the <strong>Analytics Tags</strong> section, which is where the analytics tags associated with the link are laid out plainly, alongside what each tag means.</p><p>.png)</p>',20)])])}const k=t(n,[["render",r]]);export{u as __pageData,k as default};
